@Composable
fun SelectCertificateScreen(
    onCertificateSelected: (String) -> Unit = {},
    onSkip: () -> Unit = {},
    onBack: () -> Unit = {}
) {
    val selectedCert = remember { mutableStateOf<String?>(null) }
    Surface(
        color = Color(0xFFF7EEFE),
        modifier = Modifier
            .padding(24.dp)
            .shadow(6.dp, RoundedCornerShape(16.dp))
    ) {
        Column(
            verticalArrangement = Arrangement.SpaceEvenly,
            horizontalAlignment = Alignment.CenterHorizontally,
            modifier = Modifier
                .padding(16.dp)
                .fillMaxSize()
        ) {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(bottom = 8.dp),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                IconButton(onClick = onBack) {
                    Icon(
                        Icons.AutoMirrored.Filled.ArrowBack,
                        contentDescription = "Back",
                        tint = Color(0xFF22005D)
                    )
                }
                Text(
                    text = "Skip",
                    color = Color(0xFF22005D),
                    fontWeight = FontWeight.Medium,
                    fontSize = 14.sp,
                    modifier = Modifier.clickable { onSkip() }
                )
            }

            AuthHeader("Select Certificate", "Choose your target certification (Optional)")
            SelectCertificate(onCertificateSelected = { cert ->
                selectedCert.value = cert
            })
            ButtonAuth(
                onClick = {
                    selectedCert.value?.let { onCertificateSelected(it) }
                },
                text = "Continue",
                enabled = selectedCert.value != null
            )
        }
    }
}

@Composable
fun SelectCertificate(onCertificateSelected: (String) -> Unit) {
    val selectedCert = remember { mutableIntStateOf(-1) }
    val listCerts = listOf("TOEFL", "IELTS", "Cambridge", "No Certification")

    Column(
        verticalArrangement = Arrangement.spacedBy(16.dp),
        modifier = Modifier.fillMaxWidth(0.85f)
    ) {
        listCerts.forEachIndexed { index, certName ->
            Certificate(
                name = certName,
                isSelected = selectedCert.intValue == index,
                onCertificateSelected = {
                    selectedCert.intValue = index
                    onCertificateSelected(certName)
                }
            )
        }
    }
}

@Composable
fun Certificate(
    name: String,
    isSelected: Boolean,
    onCertificateSelected: () -> Unit
) {
    val backgroundColor = if (isSelected) Color(0xFF22005D) else Color.White
    val textColor = if (isSelected) Color.White else Color(0xFF22005D)
    val borderColor = Color(0xFF22005D)

    Box(
        contentAlignment = Alignment.Center,
        modifier = Modifier
            .fillMaxWidth()
            .padding(vertical = 8.dp)
            .background(
                color = backgroundColor,
                shape = RoundedCornerShape(12.dp)
            )
            .border(
                width = 2.dp,
                color = borderColor,
                shape = RoundedCornerShape(12.dp)
            )
            .clickable { onCertificateSelected() }
            .padding(20.dp)
    ) {
        Text(
            text = name,
            fontSize = 18.sp,
            fontWeight = FontWeight.Bold,
            color = textColor
        )
    }
}

